+/*
+ * Security: sanitize user-controlled SVG to prevent DOM-based XSS.
+ * Scratch projects can contain crafted SVG (e.g., costumes) which may include
+ * <script>, <foreignObject>, event handler attributes, or javascript: URLs.
+ */
+
+const UNSAFE_TAGS = new Set([
+    'script',
+    'foreignobject'
+]);
+
+const isUnsafeUrl = value => {
+    if (!value) return false;
+    const v = String(value).trim().toLowerCase();
+    return v.startsWith('javascript:') || v.startsWith('vbscript:');
+};
+
+const sanitizeSvgDom = svgElement => {
+    if (!svgElement) return;
+
+    // Walk the tree and remove unsafe elements/attributes
+    const walk = node => {
+        if (!node || !node.childNodes) return;
+
+        // Copy because we may remove nodes while iterating
+        const children = Array.prototype.slice.call(node.childNodes);
+        for (let i = 0; i < children.length; i++) {
+            const child = children[i];
+            if (child.nodeType === 1) { // ELEMENT_NODE
+                const localName = (child.localName || child.nodeName || '').toLowerCase();
+                if (UNSAFE_TAGS.has(localName)) {
+                    node.removeChild(child);
+                    continue;
+                }
+
+                // Remove inline event handlers (onload, onclick, ...)
+                if (child.attributes && child.attributes.length) {
+                    const attrs = Array.prototype.slice.call(child.attributes);
+                    for (let j = 0; j < attrs.length; j++) {
+                        const attr = attrs[j];
+                        const name = (attr.name || '').toLowerCase();
+                        const value = attr.value;
+
+                        if (name.slice(0, 2) === 'on') {
+                            child.removeAttribute(attr.name);
+                            continue;
+                        }
+
+                        // Block javascript: / vbscript: URLs in common URL-bearing attributes
+                        if ((name === 'href' || name === 'xlink:href') && isUnsafeUrl(value)) {
+                            child.removeAttribute(attr.name);
+                            continue;
+                        }
+
+                        // Basic hardening: strip style attributes containing javascript:
+                        if (name === 'style' && /javascript:/i.test(String(value))) {
+                            child.removeAttribute(attr.name);
+                        }
+                    }
+                }
+
+                walk(child);
+            }
+        }
+    };
+
+    walk(svgElement);
+};
+
+const sanitizeSvgString = svgString => {
+    // Prefer DOM-based sanitization when available
+    /* global DOMParser, XMLSerializer */
+    if (typeof DOMParser !== 'undefined' && typeof XMLSerializer !== 'undefined') {
+        try {
+            const parser = new DOMParser();
+            const doc = parser.parseFromString(svgString, 'image/svg+xml');
+            // If parsing fails, fall back to a conservative string-based cleanup
+            if (doc.getElementsByTagName('parsererror').length) {
+                throw new Error('SVG parse error');
+            }
+            sanitizeSvgDom(doc.documentElement);
